export const 太上符四 = (bi) => {
    const u = bi.u, k = 2.6;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 1.8) * k + 1.0;
    const 線 = (書, 寬 = 0.55) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.58) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    // 太上冠：頂小鉤・大橫・左右長弧腳・上字
    出(p => p.M(X(3.75), Z(2.0)).C(X(3.85), Z(2.4), X(3.95), Z(2.7), X(4.0), Z(2.9)), 0.5);
    線(p => p.M(X(0.55), Z(3.4)).L(X(7.25), Z(3.32)), 0.62);
    出(p => p.M(X(3.85), Z(3.45)).C(X(2.6), Z(4.6), X(1.3), Z(5.4), X(0.8), Z(6.4)).L(X(0.78), Z(9.6)), 0.6);
    出(p => p.M(X(4.05), Z(3.45)).C(X(5.3), Z(4.6), X(6.6), Z(5.4), X(7.1), Z(6.4)).L(X(7.08), Z(8.2)), 0.6);
    線(p => p.M(X(3.95), Z(3.9)).L(X(3.93), Z(5.8)), 0.55);
    // 冠腳彎合
    出(p => p.M(X(0.78), Z(9.6)).C(X(0.9), Z(10.1), X(1.7), Z(10.35), X(3.0), Z(10.3)), 0.58);
    出(p => p.M(X(7.08), Z(8.2)).C(X(7.0), Z(8.9), X(6.6), Z(9.3), X(6.1), Z(9.4)), 0.58);
    線(p => p.M(X(4.05), Z(4.7)).L(X(5.1), Z(4.66)), 0.5);
    線(p => p.M(X(2.5), Z(5.9)).L(X(5.6), Z(5.84)), 0.55);
    // 敕曲核心
    線(p => p.M(X(1.7), Z(8.1)).L(X(4.6), Z(8.04)), 0.55);
    線(p => p.M(X(2.95), Z(7.4)).L(X(2.93), Z(10.0)), 0.55);
    出(p => p.M(X(2.95), Z(9.3)).L(X(2.2), Z(10.1)), 0.45);
    出(p => p.M(X(3.0), Z(9.3)).L(X(3.7), Z(10.0)), 0.45);
    線(p => p.M(X(4.6), Z(7.6)).C(X(5.9), Z(7.5), X(6.3), Z(8.3), X(5.3), Z(8.6)).C(X(4.4), Z(8.9), X(4.5), Z(9.6), X(5.5), Z(9.7)).C(X(6.1), Z(9.76), X(6.3), Z(10.1), X(6.2), Z(10.4)), 0.55);
    // 龸蓋曲
    出(p => p.M(X(2.3), Z(11.0)).C(X(3.3), Z(10.6), X(4.7), Z(10.6), X(5.7), Z(11.0)), 0.55);
    線(p => p.M(X(3.3), Z(11.6)).C(X(4.5), Z(11.5), X(4.8), Z(12.1), X(3.9), Z(12.3)).C(X(3.1), Z(12.5), X(3.2), Z(13.0), X(4.2), Z(13.05)), 0.5);
    // 密櫛帶（豎櫛二層）
    出(p => p.M(X(1.50), Z(13.6)).C(X(1.35), Z(14.2), X(1.60), Z(14.8), X(1.50), Z(15.3)), 0.42);
    出(p => p.M(X(2.25), Z(13.6)).C(X(2.10), Z(14.2), X(2.35), Z(14.8), X(2.25), Z(15.3)), 0.42);
    出(p => p.M(X(3.00), Z(13.6)).C(X(2.85), Z(14.2), X(3.10), Z(14.8), X(3.00), Z(15.3)), 0.42);
    出(p => p.M(X(3.75), Z(13.6)).C(X(3.60), Z(14.2), X(3.85), Z(14.8), X(3.75), Z(15.3)), 0.42);
    出(p => p.M(X(4.50), Z(13.6)).C(X(4.35), Z(14.2), X(4.60), Z(14.8), X(4.50), Z(15.3)), 0.42);
    出(p => p.M(X(5.25), Z(13.6)).C(X(5.10), Z(14.2), X(5.35), Z(14.8), X(5.25), Z(15.3)), 0.42);
    出(p => p.M(X(6.00), Z(13.6)).C(X(5.85), Z(14.2), X(6.10), Z(14.8), X(6.00), Z(15.3)), 0.42);
    出(p => p.M(X(1.90), Z(15.6)).C(X(1.75), Z(16.1), X(2.00), Z(16.6), X(1.90), Z(17.0)), 0.42);
    出(p => p.M(X(2.65), Z(15.6)).C(X(2.50), Z(16.1), X(2.75), Z(16.6), X(2.65), Z(17.0)), 0.42);
    出(p => p.M(X(3.40), Z(15.6)).C(X(3.25), Z(16.1), X(3.50), Z(16.6), X(3.40), Z(17.0)), 0.42);
    出(p => p.M(X(4.15), Z(15.6)).C(X(4.00), Z(16.1), X(4.25), Z(16.6), X(4.15), Z(17.0)), 0.42);
    出(p => p.M(X(4.90), Z(15.6)).C(X(4.75), Z(16.1), X(5.00), Z(16.6), X(4.90), Z(17.0)), 0.42);
    出(p => p.M(X(5.65), Z(15.6)).C(X(5.50), Z(16.1), X(5.75), Z(16.6), X(5.65), Z(17.0)), 0.42);
    // 皿框密摺
    線(p => p.M(X(1.3), Z(17.5)).L(X(1.3), Z(20.4)).L(X(6.5), Z(20.32)).L(X(6.5), Z(17.42)).L(X(1.25), Z(17.5)), 0.6);
    線(p => p.M(X(1.5), Z(18.2)).L(X(6.3), Z(18.14)), 0.45);
    線(p => p.M(X(6.2), Z(18.6)).C(X(1.9), Z(18.7), X(1.7), Z(19.3), X(2.9), Z(19.4)).L(X(5.3), Z(19.3)).C(X(6.1), Z(19.35), X(6.0), Z(19.9), X(5.2), Z(19.95)), 0.5);
    線(p => p.M(X(1.0), Z(21.0)).L(X(6.8), Z(20.92)), 0.6);
};
